    inv.status !== "paid" &&
    new Date(inv.dueDate) < nowDate &&
    inv.amountCents >= 2500000
  )) {
    active.add("Overdue invoice");
  }

  if (doc.shipments?.some(s => !s.deliveredDate && new Date(s.slaDate) < nowDate)) {
    active.add("Delayed shipment");
  }

  if (doc.supportCases?.some(c => c.status === "open" && ["high", "critical"].includes(c.severity))) {
    active.add("Escalated support");
  }

  const u = doc.usage;
  if (u && u.currentPeriodUnits <= u.priorPeriodUnits * 0.7) {
    active.add("Usage decline");
  }

  return SIGNAL_ORDER.filter(s => active.has(s));
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const doc = (await client.query("SELECT doc FROM accounts LIMIT 1")).rows[0].doc;
    const accountId = doc._id;
    const requestId = doc.request?.requestId;
    const title = doc.request?.title || "Strategic account rescue";

    const signals = deriveSignals(doc, now);
    const qualifies = QUALIFYING_TIERS.has(doc.tier) && signals.length > 0;

    const status = qualifies
      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
      : "Monitoring — no escalation required.";

    const riskSummary = signals.length > 0
      ? `${signals.length} signals: ${signals.join(", ")}`
      : "0 signals";

    const owners = qualifies
      ? OWNER_ORDER.filter(o => signals.some(s => SIGNAL_OWNERS[s] === o))
      : [];

    const topOwner = owners[0] || null;
    const nextStep = qualifies
      ? `${topOwner} recovery review by 16:00`
      : "Continue standard monitoring.";

    const dueAt = new Date(new Date(now).getTime() + 24 * 60 * 60 * 1000).toISOString();

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [accountId]);

    await client.query(
      `INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary)
       VALUES ($1, $2, $3, $4, $5, $6)`,
      [requestId, accountId, title, status, nextStep, riskSummary]
    );

    for (const owner of owners) {
      await client.query(
        `INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status)
         VALUES ($1, $2, $3, $4, $5, $6)`,
        [requestId, accountId, owner, `${owner} recovery review`, dueAt, "open"]
      );
    }

    if (qualifies) {
      const body =
        `We are reaching out to inform you that your account has been identified for priority review ` +
        `based on ${signals.length} active risk signal${signals.length !== 1 ? "s" : ""}: ` +
        `${signals.join(", ")}. Our dedicated team has been engaged to work with you on a resolution plan. ` +
        `A recovery specialist will be in contact with you shortly to discuss next steps and ensure your continued success.`;

      await client.query(
        `INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)`,
        [requestId, accountId, body]
      );

      await client.query(
        `INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible)
         VALUES ($1, $2, $3, $4, $5)`,
        [requestId, accountId, `Escalation initiated: ${riskSummary}`, now, true]
      );
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

import { readFileSync } from "node:fs";
import pg from "pg";

const cfg = JSON.parse(readFileSync(new URL("../db-config.json", import.meta.url), "utf8"));

export async function withDb(fn) {
  const client = new pg.Client({ host: cfg.host, port: cfg.port, user: cfg.user, password: cfg.password, database: cfg.database });
  await client.connect();
  await client.query('SET search_path TO "' + cfg.schema + '"');
  try { return await fn(client); } finally { await client.end(); }
}
export { cfg };

// AST-Bench V3 — live-DB lane adapters + seed/dump/teardown against the real
// Docker MongoDB (:27018) and Postgres (:5433) containers.
//
// Three lanes, ONE lane-independent fact `world` (from benchmark-derive.mjs):
//   mongo          → one document per account in collection `accounts`
//   postgres-norm  → normalized tables (shape gradient applies here)
//   postgres-jsonb → one row per account with a JSONB `doc` column + GIN index
//
// Each run gets an ISOLATED namespace so 90 concurrent-ish runs never collide:
//   mongo:    database  astbench_<ns>
//   postgres: schema    astbench_<ns>   (in db sql_hidden_cost)
//
// We reuse the proven access pattern from seed-local-databases.mjs: `mongosh`
// for Mongo, `docker exec -i psql` for Postgres. No Node DB driver is needed by
// the harness itself (the AGENT workspace gets drivers; see workspace gen).

import { spawnSync } from "node:child_process";

export const MONGO_HOST_PORT = process.env.ASTBENCH_MONGO || "127.0.0.1:27018";
export const PG_CONTAINER = process.env.ASTBENCH_PG_CONTAINER || "sql-hidden-cost-postgres";
export const PG_USER = process.env.ASTBENCH_PG_USER || "lab";
export const PG_DB = process.env.ASTBENCH_PG_DB || "sql_hidden_cost";

export const LANES = ["mongo", "postgres-norm", "postgres-jsonb"];

export function namespace({ shape, lane, agentId, repeat }) {
  return `astbench_${shape}_${lane}_${agentId}_r${repeat}`.replaceAll("-", "_");
}

// ---- low-level runners -----------------------------------------------------

function mongosh(uri, evalScript) {
  const result = spawnSync("mongosh", [uri, "--quiet", "--eval", evalScript], { encoding: "utf8", maxBuffer: 64 * 1024 * 1024 });
  if (result.status !== 0) throw new Error(`mongosh failed: ${result.stderr || result.stdout}`);
  return result.stdout || "";
}

function psql(sql, { json = false } = {}) {
  const args = ["exec", "-i", PG_CONTAINER, "psql", "-v", "ON_ERROR_STOP=1", "-U", PG_USER, "-d", PG_DB];
  if (json) args.push("-At");
  const result = spawnSync("docker", args, { input: sql, encoding: "utf8", maxBuffer: 64 * 1024 * 1024 });
  if (result.status !== 0) throw new Error(`psql failed: ${result.stderr || result.stdout}`);
  return result.stdout || "";
}

function sqlString(value) {
  return `'${String(value).replaceAll("'", "''")}'`;
}

// ---- world → normalized rows (shape-aware) ---------------------------------

// Build the normalized relational rows from the lane-independent world.
// Shape controls how many tables we split into:
//   shallow  → request row carries denormalized owner/signal-free raw columns
//   moderate → child tables for invoices/shipments/regulatory/support
//   deep     → moderate + a contacts↔owner_candidate junction (reconstruction cost)
// NOTE: NO answer-key columns (no expected_outcome / owner_groups / risk_signals).
function normalizedRows(world, shape) {
  const a = world.account;
  const rows = {
    accounts: [{ account_id: a.accountId, name: a.name, tier: a.tier, region: a.region }],
    contracts: [{ contract_id: world.contract.contractId, account_id: a.accountId, arr_cents: world.contract.arrCents, renewal_date: world.contract.renewalDate, support_plan: world.contract.supportPlan }],
    contacts: world.contacts.map((c) => ({ contact_id: c.contactId, account_id: a.accountId, role: c.role, email: c.email })),
    workflow_requests: [{ request_id: `req-${a.accountId}`, account_id: a.accountId, title: world.label || "Account review", primary_entity: "account" }],
    invoices: world.invoices.map((i) => ({ invoice_id: i.invoiceId, account_id: a.accountId, amount_cents: i.amountCents, due_date: i.dueDate, status: i.status })),
    shipments: world.shipments.map((s) => ({ shipment_id: s.shipmentId, account_id: a.accountId, order_value_cents: s.orderValueCents, sla_date: s.slaDate, delivered_date: s.deliveredDate, status: s.status })),
    regulatory_flags: world.regulatoryFlags.map((r) => ({ flag_id: r.flagId, account_id: a.accountId, type: r.type, status: r.status })),
    support_cases: world.supportCases.map((s) => ({ case_id: s.caseId, account_id: a.accountId, severity: s.severity, status: s.status })),
    usage_periods: [{ account_id: a.accountId, prior_period_units: world.usage.priorPeriodUnits, current_period_units: world.usage.currentPeriodUnits }],
    // output tables (start empty; agent must populate via live writes)
    workflow_state: [],
    owner_tasks: [],
    customer_messages: [],
    audit_events: []
  };
  if (shape === "shallow") {
    // collapse child fact tables back onto the request row (denormalized),
    // keeping account/contract/contacts + the four empty output tables.
    const inv = world.invoices, shp = world.shipments, reg = world.regulatoryFlags, sup = world.supportCases, u = world.usage;
    rows.workflow_requests = [{
      request_id: `req-${a.accountId}`, account_id: a.accountId, title: world.label || "Account review", primary_entity: "account",
      invoices_json: JSON.stringify(inv), shipments_json: JSON.stringify(shp), regulatory_json: JSON.stringify(reg), support_json: JSON.stringify(sup),
      prior_period_units: u.priorPeriodUnits, current_period_units: u.currentPeriodUnits
    }];
    delete rows.invoices; delete rows.shipments; delete rows.regulatory_flags; delete rows.support_cases; delete rows.usage_periods;
  }
  if (shape === "deep") {
    // add a many-to-many reconstruction burden: candidate owner groups + junction.
    rows.owner_candidate_groups = ["Legal", "Finance", "Customer Success", "Support"].map((g, i) => ({ owner_group: g, group_order: i }));
    rows.contact_x_owner_group = world.contacts.flatMap((c) => rows.owner_candidate_groups.map((g) => ({ contact_id: c.contactId, owner_group: g.owner_group })));
  }
  return rows;
}

// column → SQL type (text default; *_cents/_units int; *_json/doc jsonb; *_date timestamptz; customer_visible bool)
function sqlType(col) {
  if (/_cents$|_units$/.test(col)) return "bigint";
  if (/_json$/.test(col) || col === "doc") return "jsonb";
  if (/_date$/.test(col) || /_at$/.test(col) || col === "occurred_at") return "timestamptz";
  if (col === "customer_visible") return "boolean";
  return "text";
}

function createTableSql(schema, table, sampleRow, extraCols = {}) {
  const cols = { ...sampleRow, ...extraCols };
  const defs = Object.keys(cols).map((c) => `  "${c}" ${sqlType(c)}`);
  return `CREATE TABLE "${schema}"."${table}" (\n${defs.join(",\n")}\n);`;
}

function insertSql(schema, table, rows) {
  if (!rows.length) return "";
  const cols = Object.keys(rows[0]);
  const tuples = rows.map((r) => `(${cols.map((c) => {
    const v = r[c];
    if (v === null || v === undefined) return "NULL";
    if (typeof v === "boolean") return v ? "TRUE" : "FALSE";
    if (typeof v === "number") return String(v);
    if (sqlType(c) === "jsonb") return `${sqlString(typeof v === "string" ? v : JSON.stringify(v))}::jsonb`;
    return sqlString(v);
  }).join(", ")})`);
  return `INSERT INTO "${schema}"."${table}" (${cols.map((c) => `"${c}"`).join(", ")}) VALUES\n${tuples.join(",\n")};`;
}

// Empty output-table column contracts (so the schema exists before the agent writes).
const OUTPUT_TABLE_COLS = {
  workflow_state: { request_id: "", account_id: "", title: "", status: "", next_step: "", risk_summary: "" },
  owner_tasks: { request_id: "", account_id: "", owner_group: "", title: "", due_at: null, status: "" },
  customer_messages: { request_id: "", account_id: "", body: "" },
  audit_events: { request_id: "", account_id: "", event: "", occurred_at: null, customer_visible: false }
};

// Input fact-table column contracts — used when a scenario leaves a table empty
// (e.g. a negative control with no shipments), so the table still has the right
// columns for the facts reader to SELECT. Numeric/date typing flows from sqlType.
const INPUT_TABLE_COLS = {
  invoices: { invoice_id: "", account_id: "", amount_cents: 0, due_date: null, status: "" },
  shipments: { shipment_id: "", account_id: "", order_value_cents: 0, sla_date: null, delivered_date: null, status: "" },
  regulatory_flags: { flag_id: "", account_id: "", type: "", status: "" },
  support_cases: { case_id: "", account_id: "", severity: "", status: "" },
  usage_periods: { account_id: "", prior_period_units: 0, current_period_units: 0 }
};

// ---- seed -------------------------------------------------------------------

export function seed({ world, shape, lane, ns }) {
  if (lane === "mongo") return seedMongo(world, ns);
  if (lane === "postgres-jsonb") return seedJsonb(world, ns);
  return seedNorm(world, shape, ns);
}

function mongoDoc(world) {
  // One access-pattern-shaped document holding all account context.
  return {
    _id: world.account.accountId,
    name: world.account.name,
    tier: world.account.tier,
    region: world.account.region,
    contract: world.contract,
    contacts: world.contacts,
    invoices: world.invoices,
    shipments: world.shipments,
    regulatoryFlags: world.regulatoryFlags,
    supportCases: world.supportCases,
    usage: world.usage,
    request: { requestId: `req-${world.account.accountId}`, title: world.label || "Account review", primaryEntity: "account" }
  };
}

function seedMongo(world, ns) {
  const uri = `mongodb://${MONGO_HOST_PORT}/${ns}`;
  const doc = mongoDoc(world);
  const script = `
    db.dropDatabase();
    db.accounts.insertOne(${JSON.stringify(doc)});
    db.workflow_state.deleteMany({});
    db.owner_tasks.deleteMany({});
    db.customer_messages.deleteMany({});
    db.audit_events.deleteMany({});
    print("seeded:" + db.accounts.countDocuments({}));
  `;
  mongosh(uri, script);
  return { uri, kind: "mongo" };
}

function seedNorm(world, shape, ns) {
  const rows = normalizedRows(world, shape);
  const stmts = [`DROP SCHEMA IF EXISTS "${ns}" CASCADE;`, `CREATE SCHEMA "${ns}";`];
  for (const [table, data] of Object.entries(rows)) {
    if (OUTPUT_TABLE_COLS[table]) {
      stmts.push(createTableSql(ns, table, OUTPUT_TABLE_COLS[table]));
      continue;
    }
    // Prefer an explicit column contract (so empty input tables still type
    // their columns correctly); fall back to the first data row's shape.
    const sample = INPUT_TABLE_COLS[table] || data[0] || { id: "" };
    stmts.push(createTableSql(ns, table, sample));
    const ins = insertSql(ns, table, data);
    if (ins) stmts.push(ins);
  }
  psql(stmts.join("\n"));
  return { schema: ns, kind: "postgres-norm" };
}

function seedJsonb(world, ns) {
  const doc = mongoDoc(world);
  const stmts = [
    `DROP SCHEMA IF EXISTS "${ns}" CASCADE;`,
    `CREATE SCHEMA "${ns}";`,
    `CREATE TABLE "${ns}"."accounts" (account_id text PRIMARY KEY, doc jsonb NOT NULL);`,
    `CREATE INDEX ON "${ns}"."accounts" USING GIN (doc);`,
    `INSERT INTO "${ns}"."accounts" (account_id, doc) VALUES (${sqlString(doc._id)}, ${sqlString(JSON.stringify(doc))}::jsonb);`
  ];
  for (const [table, cols] of Object.entries(OUTPUT_TABLE_COLS)) {
    stmts.push(createTableSql(ns, table, cols));
  }
  psql(stmts.join("\n"));
  return { schema: ns, kind: "postgres-jsonb" };
}

// ---- dump (db-before / db-after evidence) ----------------------------------

export function dump({ lane, ns }) {
  if (lane === "mongo") {
    const uri = `mongodb://${MONGO_HOST_PORT}/${ns}`;
    const out = mongosh(uri, `
      const o = {};
      for (const c of db.getCollectionNames()) { o[c] = db.getCollection(c).find({}).toArray(); }
      print(JSON.stringify(o));
    `);
    return out.trim();
  }
  const tableList = psql(
    `SELECT table_name FROM information_schema.tables WHERE table_schema = ${sqlString(ns)} ORDER BY table_name;`,
    { json: true }
  ).trim();
  const tables = tableList ? tableList.split(/\r?\n/).filter(Boolean) : [];
  const result = {};
  for (const table of tables) {
    const json = psql(
      `SELECT coalesce(json_agg(t), '[]'::json)::text FROM "${ns}"."${table}" t;`,
      { json: true }
    ).trim();
    result[table] = JSON.parse(json || "[]");
  }
  return JSON.stringify(result);
}

// ---- teardown ---------------------------------------------------------------

export function teardown({ lane, ns }) {
  try {
    if (lane === "mongo") {
      mongosh(`mongodb://${MONGO_HOST_PORT}/${ns}`, "db.dropDatabase();");
    } else {
      psql(`DROP SCHEMA IF EXISTS "${ns}" CASCADE;`);
    }
  } catch {
    // teardown is best-effort; never fail a run on cleanup.
  }
}

#!/usr/bin/env node
// AST-Bench V3 runner — live-DB, de-leaked, 3-lane, model-pinned.
//
// One cell = { shape, lane, agentId, repeat }. Flow:
//   seed live DB (isolated namespace) -> generate de-leaked workspace ->
//   freeze git -> run agent (pinned cheap model) -> live-DB `npm test` ->
//   capture diff/tokens/cheat-signals + db-before/db-after dumps -> teardown.
//
// Usage:
//   node scripts/benchmark-run-v3.mjs --shape moderate --lane mongo --agent claude-code --repeat 1
//   (optional) --model <override>   --scenario <id>   --keep-ns

import { execFileSync, spawnSync } from "node:child_process";
import { cpSync, existsSync, mkdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { extractUsage } from "./agent-usage.mjs";
import { estimateTokensFromBytes, hashExisting, writeJson, writeText } from "./benchmark-lib.mjs";
import { LANES, namespace, seed, dump, teardown } from "./benchmark-livedb.mjs";
import { writeV3Workspace } from "./benchmark-workspace-v3.mjs";
import { PRIMARY_SCENARIO, NEGATIVE_CONTROLS, deriveExpected } from "./benchmark-derive.mjs";

// Cheap-model defaults for the smoke (config.toml defaults Codex to gpt-5.5,
// and Claude inherits the session model — so we pin both explicitly here).
// Claude resolves "claude-sonnet-4-6" only via the alias "sonnet" on this
// Bedrock backend (the literal id 400s); Codex takes the grove model id directly.
const MODEL = {
  "claude-code": process.env.ASTBENCH_CLAUDE_MODEL || "sonnet",
  "codex": process.env.ASTBENCH_CODEX_MODEL || "gpt-5.4-mini"
};

const SHAPES = ["shallow", "moderate", "deep"];
const AGENTS = ["claude-code", "codex"];
const RUN_ROOT = "benchmark/runs-v3";

// Anti-cheat contract constants (declared at module top so detectCheatSignals,
// which runs during the CLI entrypoint below, never hits a temporal-dead-zone).
// The agent's ONLY allowed edit is src/workflow.mjs. Editing protected files
// (e.g. adding a file fallback to src/db.mjs, or weakening tests/) is a cheat.
const PROTECTED_PREFIXES = ["tests/", "data/"];
const PROTECTED_FILES = ["src/db.mjs", "tests/facts.mjs", "package.json", "RULES.md", "db-config.json"];
const FALLBACK_PATTERNS = [
  /seed\.json|db-before|\.snapshot|live-snapshot/i,
  /in-?memory|localDb|LocalDb|fallback\s*(db|database|store)/i
];

if (process.argv[1] === new URL(import.meta.url).pathname) {
  const shape = valueAfter("--shape") || "moderate";
  const lane = valueAfter("--lane");
  const agentId = valueAfter("--agent");
  const repeat = Number(valueAfter("--repeat") || 1);
  const modelOverride = valueAfter("--model") || "";
  const scenarioId = valueAfter("--scenario") || PRIMARY_SCENARIO.id;
  const keepNs = process.argv.includes("--keep-ns");

  if (!SHAPES.includes(shape)) fail(`--shape must be one of ${SHAPES.join(", ")}`);
  if (!LANES.includes(lane)) fail(`--lane must be one of ${LANES.join(", ")}`);
  if (!AGENTS.includes(agentId)) fail(`--agent must be one of ${AGENTS.join(", ")}`);
  if (repeat < 1) fail("--repeat must be >= 1");

  const result = runCellV3({ shape, lane, agentId, repeat, model: modelOverride || MODEL[agentId], scenarioId, keepNs });
  console.log(`AST-Bench V3 ${result.status}: ${shape}/${lane}/${agentId}/r${repeat} model=${result.model} tokensRead=${result.tokensRead}`);
  if (result.status !== "passed") process.exitCode = 1;
}

export function runCellV3({ shape, lane, agentId, repeat, model, scenarioId = PRIMARY_SCENARIO.id, keepNs = false }) {
  // Default the model HERE so every caller (CLI + batch) is safe; passing
  // model:undefined must never reach the agent as "--model undefined" (400).
  model = model || MODEL[agentId];
  const scenario = scenarioId === PRIMARY_SCENARIO.id
    ? PRIMARY_SCENARIO
    : NEGATIVE_CONTROLS.find((s) => s.id === scenarioId) || PRIMARY_SCENARIO;
  const expected = deriveExpected(scenario);
  const ns = namespace({ shape, lane, agentId, repeat });
  const outDir = join(RUN_ROOT, shape, lane, agentId, `repeat-${repeat}`);
  const workspace = join(outDir, "workspace");

  rmSync(outDir, { recursive: true, force: true });
  mkdirSync(join(outDir, "raw-transcript"), { recursive: true });
  mkdirSync(join(outDir, "db-before"), { recursive: true });
  mkdirSync(join(outDir, "db-after"), { recursive: true });

  // 1) seed live DB + 2) generate de-leaked workspace
  const dbHandle = seed({ world: scenario, shape, lane, ns });
  writeV3Workspace({ workspace, lane, shape, ns, dbHandle, scenarioId });
  writeText(join(outDir, "db-before", "seed.json"), dump({ lane, ns }));

  const prompt = buildPrompt({ lane });
  writeText(join(outDir, "prompt.md"), prompt);

  // 3) freeze git (for honest diff vs. agent's own commits)
  const frozenSha = initGit(workspace);
  const startedAt = new Date();
  const startMs = Date.now();

  // 4) run the pinned-model agent
  const agentResult = runAgent({ agentId, workspace, prompt, outDir, model });

  // 5) live-DB-backed acceptance
  const test = spawnSync("npm", ["test"], { cwd: workspace, encoding: "utf8", maxBuffer: 32 * 1024 * 1024 });
  writeText(join(outDir, "tests.log"), `${test.stdout || ""}${test.stderr || ""}`);

  // 6) capture db-after, diff, cheat signals, tokens
  writeText(join(outDir, "db-after", "final.json"), safeDump(lane, ns));
  const diff = commandOutput("git", frozenSha ? ["diff", frozenSha, "--", "."] : ["diff", "--", "."], workspace);
  writeText(join(outDir, "diff.patch"), diff);
  const changedFiles = commandOutput("git", frozenSha ? ["diff", "--name-only", frozenSha, "--", "."] : ["diff", "--name-only", "--", "."], workspace)
    .split(/\r?\n/).filter(Boolean);
  const cheatSignals = detectCheatSignals(changedFiles, (f) => { try { return readFileSync(join(workspace, f), "utf8"); } catch { return ""; } });
  const usage = extractUsage(agentId, agentResult.transcriptText);
  const transcriptBytes = (agentResult.stdoutBytes || 0) + (agentResult.stderrBytes || 0);

  // Live-DB integrity (agent-code-INDEPENDENT): read the output tables straight
  // from the real DB namespace and confirm the agent actually persisted there.
  // A file-fallback cheat leaves the live output tables empty even if `npm test`
  // (which the agent could have pointed at a local file) printed "passed".
  const liveOutput = verifyLiveWrite(lane, ns);

  let status = agentResult.status === 0 && test.status === 0 ? "passed" : "failed";
  if (cheatSignals.length > 0) status = "failed";
  // For qualifying scenarios the live DB MUST contain the persisted workflow.
  if (status === "passed" && expected.expectsEscalation && !liveOutput.liveDbWritten) {
    status = "failed";
    cheatSignals.push("live-db-not-written");
  }

  const manifest = {
    schemaVersion: "3.0.0",
    suiteId: "ast-bench-v3",
    executionMode: "live-db",
    dbNamespace: ns,
    scenarioId,
    expectsEscalation: expected.expectsEscalation,
    shape, lane, agentId, repeat,
    model,
    agentVersion: agentVersion(agentId),
    status,
    startedAt: startedAt.toISOString(),
    finishedAt: new Date().toISOString(),
    artifacts: {
      workspace,
      prompt: join(outDir, "prompt.md"),
      rawTranscript: agentResult.transcriptPath,
      stderr: agentResult.stderrPath,
      diff: join(outDir, "diff.patch"),
      tests: join(outDir, "tests.log"),
      dbBefore: join(outDir, "db-before", "seed.json"),
      dbAfter: join(outDir, "db-after", "final.json")
    },
    metrics: {
      elapsedMs: Date.now() - startMs,
      transcriptBytes,
      tokens: usage,
      estimatedTranscriptTokens: usage.source === "measured" ? usage.totalTokens : estimateTokensFromBytes(transcriptBytes),
      diffBytes: Buffer.byteLength(diff, "utf8"),
      filesChanged: changedFiles.length,
      changedFiles,
      cheatSignals,
      liveDbWritten: liveOutput.liveDbWritten,
      liveStateRows: liveOutput.liveStateRows ?? 0,
      liveTaskRows: liveOutput.liveTaskRows ?? 0,
      retrySignals: countRetrySignals(`${agentResult.transcriptText}\n${agentResult.stderrText}\n${test.stdout || ""}\n${test.stderr || ""}`),
      testStatus: test.status === 0 ? "passed" : "failed",
      agentExitCode: agentResult.status,
      testsExitCode: test.status
    },
    evidenceSha256: hashExisting([
      join(outDir, "prompt.md"),
      agentResult.transcriptPath,
      join(outDir, "diff.patch"),
      join(outDir, "tests.log"),
      join(outDir, "db-before", "seed.json"),
      join(outDir, "db-after", "final.json")
    ])
  };

  writeJson(join(outDir, "run-manifest.json"), manifest);
  if (!keepNs) teardown({ lane, ns });
  return { status, model, tokensRead: usage.tokensRead, outDir };
}

function buildPrompt({ lane }) {
  return `You are running AST-Bench V3, a live-database coding benchmark.

Your job: implement \`src/workflow.mjs\` so it connects to the live ${lane} database
described in \`db-config.json\`, reads the account's raw facts, DERIVES the rescue
workflow exactly per \`RULES.md\`, and PERSISTS the result back to the live database
(workflow_state, owner_tasks, customer_messages, audit_events).

Then run \`npm test\` until it passes. The test connects to the live database and
checks your persisted state against the rules.

Rules:
- The answer is NOT in the data. Derive status, owners, risk signals from raw facts per RULES.md.
- Connect to the real database (see db-config.json + src/db.mjs). Do not use a flat file as the database.
- Edit ONLY src/workflow.mjs. Do NOT modify src/db.mjs, tests/, db-config.json, or the seeded data.
  src/db.mjs already connects to the live database — import withDb from it as-is.
- Do NOT add any file-based or in-memory fallback. If the database connection fails, let it fail.
- Make the smallest correct production-style change.`;
}

function runAgent({ agentId, workspace, prompt, outDir, model }) {
  if (!model) throw new Error(`runAgent: missing model for ${agentId}`);
  const transcriptPath = join(outDir, "raw-transcript", `${agentId}.jsonl`);
  const stderrPath = join(outDir, "raw-transcript", `${agentId}-stderr.log`);
  let command, args, cwd = workspace;

  if (agentId === "codex") {
    command = "codex";
    args = ["exec", "--cd", workspace, "--skip-git-repo-check", "--sandbox", "workspace-write",
      "-c", `model=${JSON.stringify(model)}`,
      "--json", "--output-last-message", resolve(join(outDir, "raw-transcript", "codex-last-message.md")), prompt];
    cwd = process.cwd();
  } else if (agentId === "claude-code") {
    command = "claude";
    args = ["-p", "--output-format", "stream-json", "--verbose", "--model", model,
      "--permission-mode", "bypassPermissions", prompt];
  } else {
    throw new Error(`No adapter for ${agentId}`);
  }

  const result = spawnSync(command, args, { cwd, encoding: "utf8", maxBuffer: 96 * 1024 * 1024 });
  mkdirSync(dirname(transcriptPath), { recursive: true });
  writeFileSync(transcriptPath, result.stdout || "");
  writeFileSync(stderrPath, result.stderr || "");
  return {
    status: result.status, transcriptPath, stderrPath,
    transcriptText: result.stdout || "", stderrText: result.stderr || "",
    stdoutBytes: Buffer.byteLength(result.stdout || "", "utf8"),
    stderrBytes: Buffer.byteLength(result.stderr || "", "utf8")
  };
}

// Anti-cheat for V3. The agent's ONLY allowed edit is src/workflow.mjs.
export function detectCheatSignals(changedFiles, readFileFn) {
  const signals = [];
  for (const file of changedFiles) {
    if (PROTECTED_FILES.includes(file) || PROTECTED_PREFIXES.some((p) => file.startsWith(p))) {
      signals.push("protected-file-modified");
      continue; // its content is moot — the edit itself is the violation
    }
    const text = readFileFn(file) || "";
    if (/\bglobalThis\.\w+\s*=|\bglobal\.\w+\s*=/.test(text)) signals.push("global-injection");
    if (FALLBACK_PATTERNS.some((re) => re.test(text))) signals.push("file-fallback-db");
  }
  return [...new Set(signals)];
}

function safeDump(lane, ns) { try { return dump({ lane, ns }); } catch (e) { return JSON.stringify({ dumpError: e.message }); } }

// Agent-code-independent live-DB check: dump the real namespace and confirm the
// agent persisted workflow_state + owner_tasks THERE (not into a local file).
function verifyLiveWrite(lane, ns) {
  try {
    const data = JSON.parse(dump({ lane, ns }));
    const stateRows = (data.workflow_state || []).length;
    const taskRows = (data.owner_tasks || []).length;
    return { liveDbWritten: stateRows >= 1 && taskRows >= 1, liveStateRows: stateRows, liveTaskRows: taskRows };
  } catch (e) {
    return { liveDbWritten: false, error: e.message };
  }

